# myapp/auth.py (refactored)
import re
from typing import Any

_KEY_PATTERN = re.compile(r'^[0-9a-f]{32}$')

def validate_api_key(key: Any) -> bool:
    """Return True if key is a 32-character lowercase hexadecimal string."""
    if not isinstance(key, str):
        return False
    return bool(_KEY_PATTERN.match(key))

# tests/test_parser.py
import pytest
from myapp.parser import parse_tool_call

def test_parse_valid_tool_call():
    raw = '{"tool": "search", "query": "python tdd"}'
    result = parse_tool_call(raw)
    assert result == {"tool": "search", "query": "python tdd"}

def test_parse_missing_tool_key():
    with pytest.raises(ValueError, match="missing 'tool' key"):
        parse_tool_call('{"query": "python tdd"}')

def test_parse_invalid_json():
    with pytest.raises(ValueError, match="invalid JSON"):
        parse_tool_call("not json")

# myapp/parser.py
import json

def parse_tool_call(raw: str) -> dict:
    """Parse a JSON tool-call string into a dict, raising ValueError on failure."""
    try:
        data = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"invalid JSON: {exc}") from exc
    if "tool" not in data:
        raise ValueError("missing 'tool' key in tool call")
    return data

# tests/test_retry.py
import pytest
from unittest.mock import MagicMock, call
from myapp.retry import retry_on_error

def test_succeeds_on_first_attempt():
    fn = MagicMock(return_value="ok")
    result = retry_on_error(fn, max_attempts=3)()
    assert result == "ok"
    assert fn.call_count == 1

def test_retries_on_transient_error():
    fn = MagicMock(side_effect=[OSError("timeout"), OSError("timeout"), "ok"])
    result = retry_on_error(fn, max_attempts=3)()
    assert result == "ok"
    assert fn.call_count == 3

def test_raises_after_max_attempts():
    fn = MagicMock(side_effect=OSError("timeout"))
    with pytest.raises(OSError):
        retry_on_error(fn, max_attempts=3)()
    assert fn.call_count == 3
